public boolean checkValueInBST(TreeNode root, int target) {
	if (root == null) return false;
	if (root.val == target) return true;
	if (target < root.val) return checkValueInBST(root.left, target);
	return checkValueInBST(root.right, target);
}

public int findSmallestInBST(TreeNode root) {
	if (root == null) throw new IllegalArgumentException("Tree cannot be empty");
	while (root.left != null) {
		root = root.left;
	}
	return root.val;
}

public int longestSubarrayWithSumK(int[] nums, int k) {
	Map<Integer, Integer> prefixSumIndices = new HashMap<>();
	prefixSumIndices.put(0, -1); // Base case: prefix sum of 0 at index -1
	int prefixSum = 0;
	int maxLength = 0;

	for (int i = 0; i < nums.length; i++) {
		prefixSum += nums[i];

		if (prefixSumIndices.containsKey(prefixSum - k)) {
			maxLength = Math.max(maxLength, i - prefixSumIndices.get(prefixSum - k));
		}

		// Only store the first occurrence of each prefix sum
		prefixSumIndices.putIfAbsent(prefixSum, i);
	}

	return maxLength;
}

public int maxPathSum(TreeNode root) {
	int[] maxSum = new int[]{Integer.MIN_VALUE};
	maxGain(root, maxSum);
	return maxSum[0];
}

private int maxGain(TreeNode node, int[] maxSum) {
	if (node == null) return 0;

	int leftGain = Math.max(maxGain(node.left, maxSum), 0);
	int rightGain = Math.max(maxGain(node.right, maxSum), 0);

	int priceNewPath = node.val + leftGain + rightGain;
	maxSum[0] = Math.max(maxSum[0], priceNewPath);

	return node.val + Math.max(leftGain, rightGain);
}
